#include "matmul_scaling_residual_add_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

// UB budget: 192 KB, shared by matmul (A, B, C, workspace) and vector ops
// We split for vector: 2 tiles for bias add and scaling
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN = 32;  // 32-byte alignment for matmul
static constexpr uint32_t MAX_TILE_M = 256;
static constexpr uint32_t MAX_TILE_N = 256;
static constexpr uint32_t MAX_TILE_K = 256;

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    MatmulScalingResidualAddCustomTilingData tiling;
    const auto &x_shape = context->GetInputShape(0)->GetOriginShape();
    const auto &w_shape = context->GetInputShape(1)->GetOriginShape();
    uint32_t M = static_cast<uint32_t>(x_shape.GetDim(0));
    uint32_t K = static_cast<uint32_t>(x_shape.GetDim(1));
    uint32_t N = static_cast<uint32_t>(w_shape.GetDim(0));

    // scalingFactor from attribute
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *scaling_ptr = attrs->GetAttrPointer<float>(0);
    float scalingFactor = 1.0f + (*scaling_ptr);  // fusing y*s + y = y*(1+s)

    // Determine tile sizes (conservative)
    uint32_t tileM = (M > MAX_TILE_M) ? MAX_TILE_M : M;
    uint32_t tileN = (N > MAX_TILE_N) ? MAX_TILE_N : N;
    uint32_t tileK = (K > MAX_TILE_K) ? MAX_TILE_K : K;

    // Number of tiles across M, N, K
    uint32_t tilesM = CeilDiv(M, tileM);
    uint32_t tilesN = CeilDiv(N, tileN);
    uint32_t tilesK = CeilDiv(K, tileK);

    // blockDim based on parallelism (up to 24 cores)
    uint32_t blockDim = tilesM * tilesN;
    if (blockDim > 24) blockDim = 24;
    if (blockDim < 1) blockDim = 1;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K);
    tiling.set_tileM(tileM);
    tiling.set_tileN(tileN);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);
    tiling.set_scalingFactor(scalingFactor);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;  // No workspace needed
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

